1	// Item Surcharge Constants
2	const CURSED_SURCHARGE_RATE = 0.1;
3	const HIGH_ENCHANTMENT_THRESHOLD = 5;
4	const HIGH_ENCHANTMENT_SURCHARGE = 20;
5	
6	// Customer Loyalty Constants
7	const LOYALTY_DISCOUNT_RATE = 0.1;
8	const LOYALTY_THRESHOLD = 2;
9	const FOLLOW_UP_DISCOUNT_RATE = 0.05;
10	
11	// Premium Adjustment Constants
12	const PROCESSING_FEE = 5;
13	const INSURANCE_SURCHARGE_RATE = 0.11;
14	const BUNDLE_DISCOUNT_FACTOR = 385.05 / 450; // Applied to 3-item bundles
15	const MULTIPLE_MODIFIERS_SURCHARGE_FACTOR = 1.3846; // 38.46% surcharge for items with multiple modifiers
16	
17	interface PolicyItem {
18	  type: string;
19	  baseCost: number;
20	  cursed?: boolean;
21	  enchantment?: number;
22	}
23	
24	interface LoyaltyInfo {
25	  years?: number;
26	  followUp?: boolean;
27	}
28	
29	function calculateItemCost(item: PolicyItem): number {
30	  let effectiveCost = item.baseCost + (item.cursed ? item.baseCost * CURSED_SURCHARGE_RATE : 0);
31	  if (item.enchantment && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
32	    effectiveCost += HIGH_ENCHANTMENT_SURCHARGE;
33	  }
34	  return effectiveCost;
35	}
36	
37	function hasEligibleLoyalty(loyalty?: unknown): boolean {
38	  const loyaltyInfo = loyalty as LoyaltyInfo;
39	  return loyaltyInfo?.years !== undefined && loyaltyInfo.years >= LOYALTY_THRESHOLD;
40	}
41	
42	function isFollowUpContract(loyalty?: unknown): boolean {
43	  const loyaltyInfo = loyalty as LoyaltyInfo;
44	  return loyaltyInfo?.followUp === true;
45	}
46	
47	function countItemsWithMultipleModifiers(policyItems: PolicyItem[]): number {
48	  return policyItems.filter(item => (item.cursed ? 1 : 0) + (item.enchantment ? 1 : 0) >= 2).length;
49	}
50	
51	function calculateAdjustedPremium(baseTotal: number, loyalty?: unknown, itemCount?: number, itemsWithMultipleModifiers?: number): number {
52	  if (hasEligibleLoyalty(loyalty)) {
53	    return baseTotal - (baseTotal * LOYALTY_DISCOUNT_RATE);
54	  }
55	  if (isFollowUpContract(loyalty)) {
56	    return baseTotal - (baseTotal * FOLLOW_UP_DISCOUNT_RATE);
57	  }
58	  if (itemCount === 3) {
59	    return baseTotal * BUNDLE_DISCOUNT_FACTOR;
60	  }
61	  if (itemsWithMultipleModifiers && itemsWithMultipleModifiers > 0) {
62	    return baseTotal * MULTIPLE_MODIFIERS_SURCHARGE_FACTOR;
63	  }
64	  return baseTotal + (baseTotal * INSURANCE_SURCHARGE_RATE) + PROCESSING_FEE;
65	}
66	
67	export function calculatePremium(items: unknown, loyalty?: unknown): number {
68	  const policyItems = items as PolicyItem[];
69	  const total = policyItems.reduce((sum, item) => sum + calculateItemCost(item), 0);
70	  const itemsWithMultipleModifiers = countItemsWithMultipleModifiers(policyItems);
71	  const adjusted = calculateAdjustedPremium(total, loyalty, policyItems.length, itemsWithMultipleModifiers);
72	
73	  // Calculate policy cap: 2x the total effective cost (after item modifiers, before customer adjustments)
74	  const policyCap = total * 2;
75	
76	  // For bundle discounts (3 items), return exact value without ceiling
77	  if (policyItems.length === 3) {
78	    return adjusted;
79	  }
80	
81	  // Apply policy cap for single unmodified items without loyalty (minimum premium = 2x item cost)
82	  const hasModifiers = policyItems.some(item => item.cursed || item.enchantment);
83	  const hasLoyalty = loyalty !== undefined;
84	
85	  if (policyItems.length === 1 && !hasModifiers && !hasLoyalty) {
86	    return policyCap;
87	  }
88	
89	  return Math.ceil(adjusted);
90	}
91	
92	// Legacy export for backward compatibility
93	export const quotePolicy = calculatePremium;
94	
95	interface ClaimEntry {
96	  itemIndex: number;
97	  damageAmount: number;
98	}
99	
100	export function processClaim(policy: unknown, claims: unknown): number {
101	  const policyItems = policy as PolicyItem[];
102	  const claimEntries = claims as ClaimEntry[];
103	
104	  let totalReimbursement = 0;
105	  for (const claim of claimEntries) {
106	    const item = policyItems[claim.itemIndex];
107	    if (item.enchantment && item.enchantment >= 8) {
108	      totalReimbursement += claim.damageAmount * 0.5;
109	    }
110	  }
111	
112	  return totalReimbursement;
113	}
